import { readFileSync } from "node:fs";
import { join } from "node:path";
import { describe, expect, it } from "vitest";
import { renderMarkdown } from "./render.js";
import { TARGETS } from "./targets.js";
import { updateFlow } from "./update.js";
const REPO_ROOT = join(__dirname, "..", "..", "..");
const UPDATE_PATHS = {
    claude: "bitfab-claude-plugin/commands/update.md",
    cursor: "bitfab-cursor-plugin/skills/bitfab-update/SKILL.md",
    codex: "bitfab-codex-plugin/skills/update/SKILL.md",
};
describe("renderMarkdown(updateFlow)", () => {
    for (const targetName of Object.keys(UPDATE_PATHS)) {
        it(`matches the committed ${targetName} update skill byte-for-byte`, () => {
            const target = TARGETS[targetName];
            const generated = renderMarkdown(updateFlow, target);
            const committedPath = join(REPO_ROOT, UPDATE_PATHS[targetName]);
            const committed = readFileSync(committedPath, "utf-8");
            expect(generated).toBe(committed);
        });
    }
});
